import{_ as n,o as a,c as e,a as l}from"./app.40d299aa.js";const b=JSON.parse('{"title":"Cursor 使用技巧","description":"","frontmatter":{},"headers":[{"level":2,"title":".cursorignore的使用","slug":"cursorignore的使用","link":"#cursorignore的使用","children":[]},{"level":2,"title":"Rules","slug":"rules","link":"#rules","children":[{"level":3,"title":"前端相关的 Cursor Rules 示例","slug":"前端相关的-cursor-rules-示例","link":"#前端相关的-cursor-rules-示例","children":[]},{"level":3,"title":"后端相关的 Cursor Rules 示例","slug":"后端相关的-cursor-rules-示例","link":"#后端相关的-cursor-rules-示例","children":[]}]}],"relativePath":"computer/Cursor.md","lastUpdated":1775055535718}'),r={name:"computer/Cursor.md"};function p(o,s,i,c,t,d){return a(),e("div",{"data-pagefind-body":!0},[...s[0]||(s[0]=[l(`<h1 id="cursor-使用技巧" tabindex="-1">Cursor 使用技巧 <a class="header-anchor" href="#cursor-使用技巧" aria-hidden="true">#</a></h1><h2 id="cursorignore的使用" tabindex="-1">.cursorignore的使用 <a class="header-anchor" href="#cursorignore的使用" aria-hidden="true">#</a></h2><p><code>.cursorignore</code> 文件类似于 <code>.gitignore</code>，用于指定在使用 <a href="https://www.cursor.so/" target="_blank" rel="noreferrer">Cursor 编辑器</a> 或相关 AI 工具过程中，哪些文件或目录应被自动忽略（即不做自动分析、搜索、补全等）。</p><p>常用的有</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">dist/</span></span>
<span class="line"><span style="color:#babed8;">build/</span></span>
<span class="line"><span style="color:#babed8;">coverage/</span></span>
<span class="line"><span style="color:#babed8;">*.log</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-hidden="true">#</a></h2><p>Cursor 的 Rules（.cursor/rules/*.md 文件）是对 AI 编程助手行为的定制规定，可以自动化团队规范、限制或增强编辑器 AI 的智能提示、重构、代码生成等能力。比如可以为不同的目录、文件类型、技术规范、约定优先级等，做出明确指引。</p><p>下面给出前端、后端常见的 Rules 书写场景和例子：</p><hr><h3 id="前端相关的-cursor-rules-示例" tabindex="-1">前端相关的 Cursor Rules 示例 <a class="header-anchor" href="#前端相关的-cursor-rules-示例" aria-hidden="true">#</a></h3><ol><li><p><strong>强制使用 eslint/prettier 规范：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/formatting.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Always format JavaScript/TypeScript, Vue, and React files according to .prettierrc and .eslintrc.</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Do not accept AI code completions that do not pass lint checks.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p><strong>避免直接改动自动生成文件：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/no-edit-generated.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Never edit files in src/generated/ or dist/ directories, except when explicitly asked.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p><strong>优先推荐函数组件（React）：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/react.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Prefer functional components over class components in all React code.</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Use hooks whenever possible for state and lifecycle management.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p><strong>Vue 约定：使用 script setup</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/vue.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> All new Vue 3 components should use &lt;script setup&gt; syntax.</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Use Composition API instead of Options API.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li></ol><hr><h3 id="后端相关的-cursor-rules-示例" tabindex="-1">后端相关的 Cursor Rules 示例 <a class="header-anchor" href="#后端相关的-cursor-rules-示例" aria-hidden="true">#</a></h3><ol><li><p><strong>敏感信息泄露保护：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/secrets.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Never suggest, generate, or accept committed secrets (API keys, passwords, etc.).</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Always use environment variables for sensitive configuration.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p><strong>Node.js 项目规范：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/node.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Default to CommonJS or ES Module syntax as per package.json type field.</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Prefer async/await over callbacks for asynchronous code.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p><strong>接口命名和结构规范：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/api.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> RESTful API endpoints should use kebab-case for URLs and camelCase for JSON body keys.</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Always include status codes and error messages in API responses.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p><strong>数据库操作约束（以 TypeORM 为例）：</strong></p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;"># </span><span style="color:#FFCB6B;">.cursor/rules/database.md</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Use parameterized queries or ORM methods instead of raw SQL to prevent SQL injection.</span></span>
<span class="line"><span style="color:#89DDFF;">-</span><span style="color:#BABED8;"> Always define explicit entity relationships (OneToMany, ManyToOne, etc.) in the model layer.</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li></ol><hr><blockquote><p>更多定制和进阶用法可参考官方文档或团队协作约定，在 <code>.cursor/rules/</code> 目录下新增/调整规则文件，持续提升 AI 助力开发体验。</p></blockquote>`,16)])])}const m=n(r,[["render",p]]);export{b as __pageData,m as default};
